const config: SizeLimitConfig = [
  {
    name: "import format from 'icu-minify/format' (production)",
    import: 'format',
    path: 'dist/esm/production/format.js',
    limit: '0.65 kB'
  },
  {
    name: "import compile from 'icu-minify/compile' (production)",
    import: 'compile',
    path: 'dist/esm/production/compile.js',
    limit: '7.1 kB'
  }
];

if (this.catalogLocales) {
  return this.catalogLocales;
} else {
  const messagesDir = path.join(this.projectRoot, this.config.extract.path);
  this.catalogLocales = new CatalogLocales({
    messagesDir,
    extension: getFormatExtension(this.config.messages.format),
    locales: this.config.extract.locales,
    sourceLocale: this.config.extract.sourceLocale
  });
  return this.catalogLocales;
}

return new Promise((resolve, reject) => {
  this.pendingResolvers.push({resolve, reject});
  this.nextSaveTask = saveTask;

  if (!this.isSaving && !this.saveTimeout) {
    // Not currently saving and no scheduled save, save immediately
    this.executeSave();
  } else if (this.saveTimeout) {
    // A save is already scheduled, reschedule to debounce
    this.scheduleSave();
  }
  // If isSaving is true and no timeout is scheduled, the current save
  // will check for pending resolvers when it completes and schedule
  // another save if needed (see finally block in executeSave)
});

if (pathname) {
  const prefixLocale = getPathnameMatch(
    pathname,
    routing.locales,
    routing.localePrefix,
    domain
  )?.locale;
  if (prefixLocale) {
    if (isLocaleSupportedOnDomain(prefixLocale, domain)) {
      locale = prefixLocale;
    } else {
      // Causes a redirect to a domain that supports the locale
      return {locale: prefixLocale, domain};
    }
  }
}

const params: GetRequestConfigParams = {
  locale: localeOverride,

  // In case the consumer doesn't read `params.locale` and instead provides the
  // `locale` (either in a single-language workflow or because the locale is
  // read from the user settings), don't attempt to read the request locale.
  get requestLocale() {
    return localeOverride
      ? Promise.resolve(localeOverride)
      : getRequestLocale();
  }
};

if (timeZone) {
  // The only way to set a time zone with `intl-messageformat` is to merge it into the formats
  // https://github.com/formatjs/formatjs/blob/8256c5271505cf2606e48e3c97ecdd16ede4f1b5/packages/intl/src/message.ts#L15
  ['date', 'time'].forEach((property) => {
    const formats = allFormats[property as keyof typeof allFormats];
    for (const [key, value] of Object.entries(formats)) {
      formats[key] = {
        timeZone,
        ...value
      };
    }
  });
}

if (hasWebAuthn) {
  // Log experimental warning
  if (options.experimental?.enableWebAuthn) {
    warnings.push("experimental-webauthn")
  } else {
    return new ExperimentalFeatureNotEnabled(
      "WebAuthn is an experimental feature. To enable it, set `experimental.enableWebAuthn` to `true` in your config"
    )
  }

  if (!adapter) return new MissingAdapter("WebAuthn requires an adapter")
  requiredMethods.push(...webauthnMethods)
}

const translations = {
  ar: {
    dir: "rtl" as const,
    twoFactor: "المصادقة الثنائية",
    twoFactorDescription: "التحقق عبر البريد الإلكتروني أو رقم الهاتف.",
    enable: "تفعيل",
    verified: "تم التحقق من ملفك الشخصي.",
  },
  he: {
    dir: "rtl" as const,
    twoFactor: "אימות דו-שלבי",
    twoFactorDescription: "אמת באמצעות אימייל או מספר טלפון.",
    enable: "הפעל",
    verified: "הפרופיל שלך אומת.",
  },
}

const translations = {
  ar: {
    dir: "rtl" as const,
    title: "جارٍ معالجة طلبك",
    description: "يرجى الانتظار بينما نعالج طلبك. لا تقم بتحديث الصفحة.",
    cancel: "إلغاء",
  },
  he: {
    dir: "rtl" as const,
    title: "מעבד את הבקשה שלך",
    description: "אנא המתן בזמן שאנו מעבדים את בקשתך. אל תרענן את הדף.",
    cancel: "ביטול",
  },
}

if (directoryResult.success) {
  const registriesResult = registriesSchema.safeParse(
    getRegistries(directoryResult.data)
  )

  if (!registriesResult.success) {
    console.error("❌ /r/registries.json validation failed:")
    console.error(registriesResult.error.format())
    hasErrors = true
  } else {
    console.log("✅ /r/registries.json payload is valid")
    console.log("✅ /r/registries.json includes all directory entries")
  }
}

for (const [registryFile, diagnostics] of Array.from(
  groupDiagnostics(report)
)) {
  logger.log(highlighter.info(formatPath(registryFile, report.cwd)))

  for (const diagnostic of diagnostics) {
    logger.error(`  - ${formatDiagnostic(diagnostic)}`)
    if (diagnostic.suggestion) {
      logger.log(`    ${diagnostic.suggestion}`)
    }
  }

  logger.break()
}

try {
  const configPath = path.resolve(config.resolvedPaths.cwd, "components.json")
  const existingConfig = JSON.parse(await fs.readFile(configPath, "utf-8"))
  existingConfig.rtl = true
  await fs.writeFile(
    configPath,
    JSON.stringify(existingConfig, null, 2) + "\n"
  )
  configSpinner.succeed("Updated components.json.")
} catch {
  configSpinner.fail("Failed to update components.json.")
  throw new Error(
    "Could not update components.json. Please manually set `rtl: true`."
  )
}

if (path.isAbsolute(filePath)) {
  addDiagnostic(context, {
    registryFile: source.registryFile,
    itemName: item.name,
    itemIndex: source.itemIndex,
    filePath,
    message: `File path "${filePath}" must be relative.`,
    suggestion:
      "Use a local file path relative to the registry.json file that declares the item.",
  })
  return null
}

if (registry.include !== undefined) {
  const result = registryIncludeSchema.safeParse(registry.include)
  if (!result.success) {
    addZodDiagnostics(result.error, registryFile, context, {
      pathPrefix: ["include"],
      suggestion: "Update include so it is an array of registry.json paths.",
    })
  } else {
    chunk.include = result.data
  }
}

items.forEach((item, itemIndex) => {
  const result = registryItemSchema.safeParse(item)
  if (!result.success) {
    addZodDiagnostics(result.error, registryFile, context, {
      itemName: getRawItemName(item),
      itemIndex,
      suggestion:
        "Update the registry item so it matches the registry item schema.",
    })
    return
  }

  registryItems.push(result.data)
})

try {
  await fs.access(options.cwd, fs.constants.W_OK)
} catch (error) {
  logger.break()
  logger.error(`The path ${highlighter.info(options.cwd)} is not writable.`)
  logger.error(
    `It is likely you do not have write permissions for this folder or the path ${highlighter.info(
      options.cwd
    )} does not exist.`
  )
  logger.break()
  process.exit(1)
}

export const octetInputParser: UtilityParser<OctetInput, ReadableStream> = {
  _input: null as any as OctetInput,
  _output: null as any as ReadableStream,
  parse(input) {
    if (input instanceof ReadableStream) {
      return input;
    }

    throw new Error(
      `Parsed input was expected to be a ReadableStream but was: ${typeof input}`,
    );
  },
};

const transforms = await multiselect({
  message: 'Select transforms to run',
  options: [
    {
      value: require.resolve('@trpc/upgrade/transforms/hooksToOptions'),
      label: 'Migrate Hooks to xxxOptions API',
    },
    {
      value: require.resolve('@trpc/upgrade/transforms/provider'),
      label: 'Migrate context provider setup',
    },
  ],
});

for (const sponsor of sponsors) {
  const { login } = sponsor;
  const section = sections.diamond.includes(login)
    ? 'diamond'
    : sections.gold.includes(login)
      ? 'gold'
      : sections.silver.includes(login)
        ? 'silver'
        : sections.bronze.includes(login)
          ? 'bronze'
          : 'other';

  buckets[section].push(sponsor);
}

run(async () => {
  const sandbox = new JustBashSandboxSession(
    await Sandbox.create({ overlayRoot: process.cwd() }),
  );

  const result = await sandboxAgent.generate({
    prompt:
      'Write a haiku about TypeScript to a file named "haiku.txt", then read it back and summarize what it says.',
    experimental_sandbox: sandbox,
  });

  console.log(result.text);
});

run(async () => {
  const result = await agent.generate({
    prompt:
      'Four friends ran a total of 26.54 miles. ' +
      'The friend who ran the farthest ran 12.63 miles. ' +
      'The friend who ran the shortest amount ran 3.67 miles. ' +
      'If the other two friends ran the same amount, how much did each of the other friend run?',
  });

  // extract answer from done tool call
  const toolCall = result.staticToolCalls[0]; // tool call from final step
  if (toolCall?.toolName === 'done') {
    console.log(toolCall.input.answer);
  }
});

run(async () => {
  const result = await agent.stream({
    prompt:
      'Four friends ran a total of 26.54 miles. ' +
      'The friend who ran the farthest ran 12.63 miles. ' +
      'The friend who ran the shortest amount ran 3.67 miles. ' +
      'If the other two friends ran the same amount, how much did each of the other friend run?',
  });

  printFullStream({ result });
});

return defineEventHandler(async (event: any) => {
  // Extract the `prompt` from the body of the request
  const { prompt } = await readBody(event);

  // Ask OpenAI for a streaming chat completion given the prompt
  const result = streamText({
    model: openai('gpt-4o'),
    prompt,
  });

  // Respond with the stream
  return createUIMessageStreamResponse({
    stream: toUIMessageStream({ stream: result.stream }),
  });
});

switch (output) {
  case 'object':
    return objectOutputStrategy(asSchema(schema!));
  case 'array':
    return arrayOutputStrategy(asSchema(schema!));
  case 'enum':
    return enumOutputStrategy(enumValues! as Array<string>);
  case 'no-schema':
    return noSchemaOutputStrategy;
  default: {
    const _exhaustiveCheck: never = output;
    throw new Error(`Unsupported output: ${_exhaustiveCheck}`);
  }
}

if (supportsAdaptiveThinking) {
  const effort = mapReasoningToProviderEffort({
    reasoning,
    effortMap: {
      minimal: 'low' as const,
      low: 'low' as const,
      medium: 'medium' as const,
      high: 'high' as const,
      xhigh: supportsXhighEffort ? ('xhigh' as const) : ('max' as const),
    },
    warnings,
  });
  return { thinking: { type: 'adaptive' }, effort };
}

if (needsToUIMessageStreamImport) {
  // Add import for toUIMessageStream from @ai-sdk/llamaindex
  const llamaIndexImport = j.importDeclaration(
    [j.importSpecifier(j.identifier('toUIMessageStream'))],
    j.literal('@ai-sdk/llamaindex'),
  );

  // Find the first import declaration to add the new import after it
  const firstImport = root.find(j.ImportDeclaration).at(0);
  if (firstImport.length > 0) {
    firstImport.insertAfter(llamaIndexImport);
  } else {
    // If no imports exist, add at the beginning
    root.get().node.body.unshift(llamaIndexImport);
  }
}

app.post('/api/notify', async c => {
  const body = await c.req.json();
  if (body.dbPath) {
    remoteDbPath = body.dbPath;
  }
  // Reload database from disk, using the remote dbPath if provided so the
  // viewer works even when started from a different directory than the app.
  await reloadDb(remoteDbPath);
  broadcastToClients('update', body);
  return c.json({ success: true });
});

if (googleOptions) {
  const { googleSearch: imagenGoogleSearch, ...imagenOptions } =
    googleOptions;
  if (imagenGoogleSearch != null) {
    warnings.push({
      type: 'unsupported',
      feature: 'googleSearch',
      details:
        'Google Search grounding is only supported on Gemini image models.',
    });
  }
  Object.assign(parameters, imagenOptions);
}

if (hasTools && isAgent) {
  warnings.push({
    type: 'other',
    message:
      'google.interactions: tools are not supported when an agent is set; tools will be omitted from the request body.',
  });
} else if (hasTools) {
  const prepared = prepareGoogleInteractionsTools({
    tools: options.tools,
    toolChoice: options.toolChoice,
  });
  toolsForBody = prepared.tools;
  toolChoiceForBody = prepared.toolChoice;
  warnings.push(...prepared.toolWarnings);
}

if (isAgent && !isTerminalStatus(response.status)) {
  const polled = await pollGoogleInteractionUntilTerminal({
    baseURL: this.config.baseURL,
    interactionId: response.id,
    headers: mergedHeaders,
    fetch: this.config.fetch,
    abortSignal: options.abortSignal,
    timeoutMs: pollingTimeoutMs,
  });
  response = polled.response;
  rawResponse = polled.rawResponse;
  responseHeaders = polled.responseHeaders ?? responseHeaders;
}
